"""
Injectable LLM clients (Anthropic, OpenAI, mock). No direct SDK calls elsewhere.
"""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any, Protocol, runtime_checkable


@runtime_checkable
class LLMClient(Protocol):
    def complete(
        self,
        *,
        system: str,
        user: str,
        max_tokens: int = 4096,
        temperature: float = 0.0,
    ) -> str: ...


class AnthropicLLMClient:
    def __init__(self, *, api_key: str, model: str) -> None:
        from anthropic import Anthropic

        self._model = model
        self._client = Anthropic(api_key=api_key or "")

    def complete(
        self,
        *,
        system: str,
        user: str,
        max_tokens: int = 4096,
        temperature: float = 0.0,
    ) -> str:
        msg = self._client.messages.create(
            model=self._model,
            max_tokens=max_tokens,
            temperature=temperature,
            system=system,
            messages=[{"role": "user", "content": user}],
        )
        parts: list[str] = []
        for block in msg.content:
            if hasattr(block, "text"):
                parts.append(block.text)
        return "".join(parts)


class OpenAILLMClient:
    def __init__(self, *, api_key: str, model: str) -> None:
        from openai import OpenAI

        self._model = model
        self._client = OpenAI(api_key=api_key or "")

    def complete(
        self,
        *,
        system: str,
        user: str,
        max_tokens: int = 4096,
        temperature: float = 0.0,
    ) -> str:
        resp = self._client.chat.completions.create(
            model=self._model,
            max_tokens=max_tokens,
            temperature=temperature,
            messages=[
                {"role": "system", "content": system},
                {"role": "user", "content": user},
            ],
        )
        choice = resp.choices[0].message
        return (choice.content or "").strip()


@dataclass
class MockLLMClient:
    """Returns scripted text; records prompts for assertions."""

    responses: list[str]
    calls: list[dict[str, Any]] = field(default_factory=list)
    prompt_must_contain: tuple[str, ...] = ()

    def complete(
        self,
        *,
        system: str,
        user: str,
        max_tokens: int = 4096,
        temperature: float = 0.0,
    ) -> str:
        for needle in self.prompt_must_contain:
            if needle not in system and needle not in user:
                raise AssertionError(f"mock LLM: expected prompt to contain {needle!r}")
        self.calls.append(
            {
                "system": system,
                "user": user,
                "max_tokens": max_tokens,
                "temperature": temperature,
            }
        )
        if not self.responses:
            return ""
        return self.responses.pop(0)


def llm_client_from_settings() -> LLMClient:
    """Factory using `noosphere.config.get_settings()`.

    Reads the *effective* provider/model/key from settings, which respects
    the operator's preference but auto-falls-back to whichever provider
    actually has credentials in the environment. This is what lets the
    GitHub Actions workflow work with only ``OPENAI_API_KEY`` set — the
    default preference is ``anthropic``, but the effective provider flips
    to ``openai`` when Anthropic's env var is empty.
    """
    from noosphere.config import get_settings

    s = get_settings()
    provider = s.effective_llm_provider()
    key = s.effective_llm_api_key()
    model = s.effective_llm_model()
    if provider == "openai":
        return OpenAILLMClient(api_key=key, model=model)
    return AnthropicLLMClient(api_key=key, model=model)

        if r is None:
            return None
        return DriftEvent.model_validate_json(r.payload_json)

def list_drift_events(self, *, limit: int = 500) -> list[DriftEvent]:
    with self.session() as s:
        rows = s.exec(select(StoredDriftEvent)).all()[:limit]
        out: list[DriftEvent] = []
        for r in rows:
            try:
                out.append(DriftEvent.model_validate_json(r.payload_json))
            except Exception:
                continue
        return out

# --- Conclusion (tiered) ---
def put_conclusion(self, c: Conclusion) -> None:
    row = StoredConclusion(id=c.id, payload_json=c.model_dump_json())
    with self.session() as s:
        existing = s.get(StoredConclusion, c.id)
        if existing:
            existing.payload_json = row.payload_json
            s.add(existing)
        else:
            s.add(row)
        s.commit()
    embedded = False
    try:
        from noosphere.embedding_pipeline import embed_conclusion_with_store

        embedded = embed_conclusion_with_store(self, c)
    except Exception:
        # Embedding is best-effort; the nightly backfill treats a missing
        # current-model embedding as the durable retry queue.
        pass
    if embedded:
        try:
            from noosphere.conclusions import run_scaled_coherence_for_conclusion

            run_scaled_coherence_for_conclusion(c, self)
        except Exception:
            pass

def get_conclusion(self, conclusion_id: str) -> Optional[Conclusion]:
    with self.session() as s:
        r = s.get(StoredConclusion, conclusion_id)
        if r is not None:
            return Conclusion.model_validate_json(r.payload_json)
    return self._get_prisma_conclusion(conclusion_id)

def list_conclusions(self) -> list[Conclusion]:
    with self.session() as s:
        rows = s.exec(select(StoredConclusion)).all()
        stored = [Conclusion.model_validate_json(r.payload_json) for r in rows]
    seen = {conclusion.id for conclusion in stored}
    return [
        *stored,
        *[
            conclusion
            for conclusion in self._list_prisma_conclusions()
            if conclusion.id not in seen
        ],
    ]

@staticmethod
def _json_string_list(value: Any | None) -> list[str]:
    if not value:
        return []
    if isinstance(value, list):
        return [str(item) for item in value if isinstance(item, str)]
    if not isinstance(value, str):
        return []
    try:
        parsed = json.loads(value)
    except json.JSONDecodeError:
        return []
    if not isinstance(parsed, list):
        return []
    return [str(item) for item in parsed if isinstance(item, str)]

@staticmethod
def _confidence_tier(value: str | None) -> ConfidenceTier:
    raw = (value or "").strip().lower()
    if raw == "firm":
        return ConfidenceTier.HIGH
    if raw in {tier.value for tier in ConfidenceTier}:
        return ConfidenceTier(raw)
    return ConfidenceTier.MODERATE

def _has_prisma_conclusion_table(self) -> bool:

    SQLite stores datetimes without tz info (the SQLAlchemy column is
    ``DateTime`` not ``DateTime(timezone=True)``). To keep comparisons
    well-defined regardless of how the caller passes ``since``/``until``
    we drop tz info after converting to UTC.
    """
    if dt.tzinfo is not None:
        return dt.astimezone(timezone.utc).replace(tzinfo=None)
    return dt


def fetch_articles_since(
    store: Any,
    *,
    since: datetime,
    until: datetime | None = None,
    site_base: str | None = None,
) -> list[ArticleForExport]:
    """Return print-ready article rows from the public table.

    The selection mirrors the web's "what's published" rule: ``kind ==
    'ARTICLE'`` and ``published_at >= since``. Anything outside that
    window or hidden in private tables is filtered at the SQL level —
    not in Python — so this CLI can never expand its visibility by
    accident.
    """
    base = (site_base or _public_site_base()).rstrip("/")
    since_naive = _as_utc_naive(since)
    until_naive = _as_utc_naive(until) if until is not None else None
    with store.session() as session:
        rows: list[PublishedConclusion] = list(
            session.exec(
                select(PublishedConclusion)
                .where(PublishedConclusion.kind == "ARTICLE")
                .where(PublishedConclusion.published_at >= since_naive)
                .order_by(PublishedConclusion.published_at)
            ).all()
        )
        if until_naive is not None:
            rows = [
                r for r in rows if _as_utc_naive(r.published_at) <= until_naive
            ]

        # One sweep for signatures so we don't N+1 the table when an
        # operator exports a quarter's worth of work.
        slugs = sorted({r.slug for r in rows})
        signatures: dict[tuple[str, int], str] = {}
        if slugs:
            for sig in session.exec(
                select(PublicationSignature).where(
                    PublicationSignature.slug.in_(slugs)  # type: ignore[attr-defined]
                )
            ).all():
                signatures[(sig.slug, sig.version)] = sig.key_fingerprint

    out: list[ArticleForExport] = []
    for row in rows:
        payload = _safe_payload(row.payload_json)
        article_payload = payload.get("article") if isinstance(payload, dict) else {}
        body_markdown = ""
        endnotes: list[ArticleEndnote] = []
        if isinstance(article_payload, dict):
            body_markdown = str(article_payload.get("bodyMarkdown") or "")
            for c in article_payload.get("citations") or []:
                if not isinstance(c, dict):
                    continue
                public_url = c.get("public_url") or c.get("publicUrl")
                title = (
                    str(c.get("source_conclusion_text") or "").strip()
                    or str(c.get("quoted_span") or "").strip()
                    or str(c.get("source_id") or "").strip()
                    or str(c.get("label") or "").strip()
                )
                endnotes.append(
                    ArticleEndnote(
                        label=str(c.get("label") or ""),
                        title=title or "Source",
                        kind=str(c.get("source_kind") or "") or None,
                        url=str(public_url).strip() or None
                        if public_url
                        else None,
                    )
                )
        for block in payload.get("citations") or []:
            if not isinstance(block, dict):
                continue
            fmt = str(block.get("format") or "").upper()
            text = str(block.get("block") or "").strip()
            if not text:
                continue
            endnotes.append(
                ArticleEndnote(
                    label=fmt or "REF",
                    title=f"{fmt or 'REF'} citation",
                    bibliographic=text,
                )
            )

        title = (
            str(payload.get("conclusionText") or "").strip()
            if isinstance(payload, dict)
            else ""
        ) or row.slug
        methodology = None
        if isinstance(payload, dict):
            method_block = payload.get("methodology") or {}
            if isinstance(method_block, dict):
                profiles = method_block.get("profiles") or []
                if profiles and isinstance(profiles[0], dict):
                    methodology = str(profiles[0].get("patternType") or "") or None

        confidence = (
            float(row.discounted_confidence)
            if row.discounted_confidence is not None
            else None
        )
        confidence_context = None
        if row.stated_confidence:
            confidence_context = (
                f"stated {int(round(float(row.stated_confidence) * 100))}%"
            )

        canonical_url = f"{base}/c/{row.slug}"
        out.append(
            ArticleForExport(
                slug=row.slug,
                version=row.version,
                title=title,
                byline="Theseus",
                published_at=row.published_at,
                body_markdown=body_markdown,
                methodology=methodology,
                confidence=confidence,
                confidence_context=confidence_context,
                mqs_composite=None,
                canonical_url=canonical_url,
                signature_fingerprint=signatures.get((row.slug, row.version)),
                endnotes=tuple(endnotes),
            )
        )
    return out


def _safe_payload(payload_json: str | None) -> dict[str, Any]:
    if not payload_json:
        return {}
    try:
        value = json.loads(payload_json)
    except (TypeError, ValueError, json.JSONDecodeError):
        return {}
    return value if isinstance(value, dict) else {}


# ── HTML composition ────────────────────────────────────────────────────────


