        generated_at: String(parsed.generated_at ?? ""),
        review_updated_at: parsed.review_updated_at
          ? String(parsed.review_updated_at)
          : undefined,
        tex_path: path.join(dir, "paper.tex"),
        pdf_path: pdfExists ? pdf : null,
      });
    } catch {
      continue;
    }
  }
  return out;
}

